      <input type="password" placeholder="Mot de passe" />
      <button type="submit">Se connecter</button>
    </form>
  );
}

import { useRef, useState } from 'react';

function ReactionGame() {
  const [message, setMessage] = useState('En attente...');
  const timerRef = useRef(null);

  const handleStart = () => {
    if (timerRef.current) clearTimeout(timerRef.current);
    setMessage('Timer démarré ! 5 secondes...');
    timerRef.current = setTimeout(() => {
      setMessage('🎉 BRAVO ! 5 secondes sont écoulées !');
      timerRef.current = null;
    }, 5000);
  };

  const handleCancel = () => {
    if (timerRef.current) {
      clearTimeout(timerRef.current);
      timerRef.current = null;
      setMessage('Timer annulé !');
    }
  };

  return (
    <div>
      <p>{message}</p>
      <button onClick={handleStart}>Démarrer</button>
      <button onClick={handleCancel}>Annuler</button>
    </div>
  );
}

import { useRef, useState, useEffect } from 'react';

function ResizableBox() {
  const boxRef = useRef(null);
  const [dimensions, setDimensions] = useState({ width: 0, height: 0 });

  const updateDimensions = () => {
    if (boxRef.current) {
      setDimensions({
        width: boxRef.current.clientWidth,
        height: boxRef.current.clientHeight
      });
    }
  };

  useEffect(() => {
    updateDimensions();
    window.addEventListener('resize', updateDimensions);
    return () => window.removeEventListener('resize', updateDimensions);
  }, []);

  return (
    <div>
      <div
        ref={boxRef}
        style={{
          width: '200px',
          height: '150px',
          resize: 'both',
          overflow: 'auto',
          border: '2px solid blue',
          padding: '10px'
        }}
      >
        Redimensionnez-moi !
      </div>
      <p>Dimensions : {dimensions.width} x {dimensions.height} px</p>
    </div>
  );
}

